import{_ as o}from"./chunks/config-page.LA-f_I6f.js";import{_ as e,o as r,c as s,ag as i}from"./chunks/framework.CvgP6Fyv.js";const n="/images/git-remote-guide/github-1.png",g="/images/git-remote-guide/github-2.png",a="/images/git-remote-guide/github-3a.png",l="/images/git-remote-guide/github-3b.png",p="/images/git-remote-guide/github-4.png",c="/images/git-remote-guide/github-5.png",d="/images/git-remote-guide/github-6.png",h="/images/git-remote-guide/github-7.png",u="/images/git-remote-guide/github-8.png",m="/images/git-remote-guide/github-9.png",b="/images/git-remote-guide/github-10.png",x=JSON.parse('{"title":"GitHub 配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/github.md","filePath":"guide/github.md","lastUpdated":1776390021000}'),_={name:"guide/github.md"};function k(T,t,S,P,f,H){return r(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="github-配置指南" tabindex="-1">GitHub 配置指南 <a class="header-anchor" href="#github-配置指南" aria-label="Permalink to &quot;GitHub 配置指南&quot;">​</a></h1><p>本文介绍如何使用 GitHub 作为远程仓库，完成仓库创建、Token 认证和软件配置。</p><h2 id="_1-创建远程仓库" tabindex="-1">1. 创建远程仓库 <a class="header-anchor" href="#_1-创建远程仓库" aria-label="Permalink to &quot;1. 创建远程仓库&quot;">​</a></h2><ol><li><p>访问 <a href="https://github.com/" target="_blank" rel="noopener noreferrer">GitHub</a> 注册并登录。</p></li><li><p>点击右上角「<strong>+</strong>」→「<strong>New repository</strong>」。</p><p><img src="'+n+'" alt="新建仓库"></p></li><li><p>填写仓库名称（如 <code>my-sts-mods</code>），选择 <strong>Public</strong> 或 <strong>Private</strong>，点击「<strong>Create repository</strong>」。</p><ul><li><strong>Public</strong> — 公开仓库，所有人可见。队友无需注册 GitHub 账号即可拉取，但上传仍需要账号和认证。</li><li><strong>Private</strong> — 私密仓库，仅邀请的人可见。所有队友都必须注册账号并被邀请后才能使用。</li></ul><p><img src="'+g+'" alt="创建仓库"></p></li><li><p>仓库创建后，复制页面上的 HTTPS 地址（格式为 <code>https://github.com/用户名/仓库名.git</code>）。</p><ul><li><p><strong>新建的空仓库</strong>：在 Quick setup 区域选择「<strong>HTTPS</strong>」，点击右侧复制按钮。</p><p><img src="'+a+'" alt="复制仓库地址（空仓库）"></p></li><li><p><strong>已有文件的仓库</strong>：点击绿色「<strong>Code</strong>」按钮，在「<strong>HTTPS</strong>」标签页下复制地址。</p><p><img src="'+l+'" alt="复制仓库地址（已有内容）"></p></li></ul></li></ol><h2 id="_2-认证方式与-token-配置" tabindex="-1">2. 认证方式与 Token 配置 <a class="header-anchor" href="#_2-认证方式与-token-配置" aria-label="Permalink to &quot;2. 认证方式与 Token 配置&quot;">​</a></h2><h3 id="认证方式" tabindex="-1">认证方式 <a class="header-anchor" href="#认证方式" aria-label="Permalink to &quot;认证方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>适用场景</th><th>说明</th></tr></thead><tbody><tr><td><strong>HTTPS</strong>（推荐）</td><td>所有仓库</td><td>需要用户名 + Personal Access Token，可正常上传和拉取</td></tr><tr><td><strong>SSH</strong></td><td>所有仓库</td><td>已配置 SSH 密钥的用户可使用</td></tr><tr><td><strong>免密</strong></td><td>仅 Public 仓库只读</td><td>只能拉取，<strong>无法上传</strong>。适合只需要跟随他人存档、不需要自己上传的场景</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">只想跟随朋友的存档？</p><p>如果你<strong>不需要上传</strong>，只想拉取朋友的 Public 仓库，可以选择「免密」，无需创建 Token — 跳过下方第 5–10 步，直接到<a href="#_3-配置-sync-the-spire">第 3 节</a>即可。</p></div><h3 id="创建-personal-access-token" tabindex="-1">创建 Personal Access Token <a class="header-anchor" href="#创建-personal-access-token" aria-label="Permalink to &quot;创建 Personal Access Token&quot;">​</a></h3><p>使用 HTTPS 认证需要创建一个 Personal Access Token (PAT) 替代密码。</p><ol start="5"><li><p>点击右上角头像 →「<strong>Settings</strong>」。</p><p><img src="'+p+'" alt="进入 Settings"></p></li><li><p>滚动到左侧栏最底部，点击「<strong>Developer settings</strong>」。</p><p><img src="'+c+'" alt="Developer settings"></p></li><li><p>依次展开「<strong>Personal access tokens</strong>」→ 选择「<strong>Tokens (classic)</strong>」→ 点击「<strong>Generate new token</strong>」→「<strong>Generate new token (classic)</strong>」。</p><p><img src="'+d+'" alt="生成 Token 入口"></p></li><li><p>填写以下信息：</p><ul><li><strong>Note</strong>：填写备注，如 <code>Sync the Spire</code></li><li><strong>Expiration</strong>：选择过期时间（建议 <code>No expiration</code>，或按需设置）</li><li><strong>Scopes</strong>：勾选 <code>repo</code>（完整仓库访问权限）</li></ul><p><img src="'+h+'" alt="填写 Token 信息"></p></li><li><p>滚动到页面底部，点击「<strong>Generate token</strong>」生成 Token。</p><p><img src="'+u+'" alt="Generate token"></p></li><li><p>生成成功后，立即复制显示的 Token（以 <code>ghp_</code> 开头的字符串）。</p><p><img src="'+m+'" alt="复制 Token"></p></li></ol><div class="danger custom-block"><p class="custom-block-title">Token 仅显示一次</p><p>生成后立即复制保存，关闭页面后将无法再查看。如果遗忘，需要重新生成。</p></div><h2 id="_3-配置-sync-the-spire" tabindex="-1">3. 配置 Sync the Spire <a class="header-anchor" href="#_3-配置-sync-the-spire" aria-label="Permalink to &quot;3. 配置 Sync the Spire&quot;">​</a></h2><ol start="11"><li><p>打开 Sync the Spire，在配置页面依次填写：</p><ul><li><strong>远程仓库 URL</strong>：粘贴第 4 步复制的仓库地址</li><li><strong>用户昵称</strong>：随意填写，用于区分不同设备/玩家</li><li><strong>鉴权方式</strong>：选择「<strong>HTTPS</strong>」，然后填入你的 <strong>GitHub 用户名</strong>和刚才生成的 <strong>Token</strong>（作为密码）</li><li><strong>游戏安装路径</strong> / <strong>存档路径</strong>：手动填写或点击「自动查找」</li><li>确认无误后，点击「<strong>保存并初始化</strong>」</li></ul><p><img src="'+o+'" alt="Sync the Spire 配置页"></p></li></ol><h2 id="_4-邀请队友" tabindex="-1">4. 邀请队友 <a class="header-anchor" href="#_4-邀请队友" aria-label="Permalink to &quot;4. 邀请队友&quot;">​</a></h2><ol start="12"><li><p>进入仓库页面，点击顶部「<strong>Settings</strong>」→ 左侧「<strong>Collaborators</strong>」→「<strong>Add people</strong>」，输入朋友的 GitHub 用户名或邮箱发送邀请。</p><p><img src="'+b+'" alt="邀请协作者"></p></li><li><p>朋友接受邀请后，需要各自创建自己的 PAT（重复第 5–10 步），然后在 Sync the Spire 中填入<strong>同一个仓库地址</strong> + <strong>自己的</strong>用户名和 Token 即可。</p></li></ol>',16)])])}const G=e(_,[["render",k]]);export{x as __pageData,G as default};
